package com.example.alcoholictimer

import android.content.Intent
import android.os.Bundle
import androidx.activity.compose.setContent
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

class MainActivity : BaseActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // кЄИм£Љ нГАмЭіл®Єк∞А мІДнЦЙ м§СмЭЄмІА нЩХмЭЄнХШк≥† м†Бм†ИнХЬ нЩФл©імЬЉл°Ь мЭілПЩ
        checkCurrentStateAndNavigate()
    }

    override fun getScreenTitle(): String = "кЄИм£Љ нГАмЭіл®Є"

    override fun setupContentView() {
        setContent {
            MainScreen()
        }
    }

    @Composable
    private fun MainScreen() {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(16.dp),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Text(
                text = "Alcoholic Timer",
                fontSize = 24.sp,
                modifier = Modifier.padding(bottom = 16.dp)
            )
            Button(onClick = {
                val intent = Intent(this@MainActivity, StartActivity::class.java)
                startActivity(intent)
            }) {
                Text("мЛЬмЮСнХШкЄ∞")
            }
        }
    }

    private fun checkCurrentStateAndNavigate() {
        val sharedPref = getSharedPreferences("user_settings", MODE_PRIVATE)
        val isSobrietyStarted = sharedPref.contains("start_time")

        if (isSobrietyStarted) {
            // кЄИм£Љк∞А мІДнЦЙ м§СмЭіл©і StatusActivityл°Ь мЭілПЩ
            val intent = Intent(this, StatusActivity::class.java)
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
            startActivity(intent)
            overridePendingTransition(0, 0)
        } else {
            // кЄИм£Љк∞А мЛЬмЮСлРШмІА мХКмХШмЬЉл©і StartActivityл°Ь мЭілПЩ
            val intent = Intent(this, StartActivity::class.java)
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
            startActivity(intent)
            overridePendingTransition(0, 0)
        }
        // MainActivityлКФ л∞±мК§нГЭмЧРмДЬ м†Ьк±∞
        finish()
        overridePendingTransition(0, 0)
    }
}

